class Solution {
    public int clumsy(int n) {
        int res = n;
        int op = 0;
        n--;
        while (n > 0) {
            if (op % 4 == 0) res *= n;
            if (op % 4 == 1) res /= n;
            if (op % 4 == 2) res += n;
            if (op % 4 == 3) res -= n;
            op++;
            n--;
        }
        return res;
    }
}
